class Solution {
    public long findMaximumNumber(long k, int x) {
        long price = 0;
        long num = 1;
        while (price <= k) {
            price = calculatePrice(num, x);
            num++;
        }
        return num - 1;
    }
    private long calculatePrice(long num, int x) {
        long price = 0;
        while (num > 0) {
            if ((num & 1) == 1) {
                price++;
            }
            num >>= x;
        }
        return price;
    }
}
